/**
 * MMS Error Classes
 *
 * Typed error classes for consistent error handling across the application.
 * Each error includes a code for client-side handling and logging.
 *
 * Error code format: CATEGORY_NNN
 * - FILE_001-099: File/CSV processing errors
 * - ROW_001-099: Row/record validation errors
 * - SYS_001-099: System/infrastructure errors
 * - BUS_001-099: Business logic errors
 * - AUTH_001-099: Authentication/authorization errors
 * - EXT_001-099: External system errors (Maximo, etc.)
 *
 * @see specs/004-backend-specification.md Section 4.15
 */

/**
 * Base error class for all MMS errors
 */
export abstract class MmsError extends Error {
  abstract readonly code: string;
  abstract readonly statusCode: number;
  readonly isOperational: boolean = true;
  readonly timestamp: Date = new Date();
  readonly context?: Record<string, unknown>;

  constructor(message: string, context?: Record<string, unknown>) {
    super(message);
    this.name = this.constructor.name;
    this.context = context;
    Error.captureStackTrace(this, this.constructor);
  }

  toJSON() {
    return {
      name: this.name,
      code: this.code,
      message: this.message,
      statusCode: this.statusCode,
      timestamp: this.timestamp.toISOString(),
      ...(this.context && { context: this.context }),
    };
  }
}

// =============================================================================
// Validation Errors (400)
// =============================================================================

export class ValidationError extends MmsError {
  readonly code = 'BUS_001';
  readonly statusCode = 400;
  readonly field?: string;
  readonly errors?: Array<{ field: string; message: string }>;

  constructor(
    message: string,
    options?: {
      field?: string;
      errors?: Array<{ field: string; message: string }>;
      context?: Record<string, unknown>;
    }
  ) {
    super(message, options?.context);
    this.field = options?.field;
    this.errors = options?.errors;
  }
}

export class CsvValidationError extends MmsError {
  readonly code = 'FILE_001';
  readonly statusCode = 400;
  readonly row?: number;
  readonly column?: string;

  constructor(
    message: string,
    options?: {
      row?: number;
      column?: string;
      context?: Record<string, unknown>;
    }
  ) {
    super(message, options?.context);
    this.row = options?.row;
    this.column = options?.column;
  }
}

export class RowValidationError extends MmsError {
  readonly code = 'ROW_001';
  readonly statusCode = 400;
  readonly row: number;
  readonly column?: string;
  readonly value?: unknown;

  constructor(
    message: string,
    row: number,
    options?: {
      column?: string;
      value?: unknown;
      context?: Record<string, unknown>;
    }
  ) {
    super(message, options?.context);
    this.row = row;
    this.column = options?.column;
    this.value = options?.value;
  }
}

export class FileError extends MmsError {
  readonly code = 'FILE_002';
  readonly statusCode = 400;
  readonly filePath?: string;
  readonly operation?: string;

  constructor(
    message: string,
    options?: {
      filePath?: string;
      operation?: string;
      context?: Record<string, unknown>;
    }
  ) {
    super(message, options?.context);
    this.filePath = options?.filePath;
    this.operation = options?.operation;
  }
}

// =============================================================================
// Authentication Errors (401)
// =============================================================================

export class AuthenticationError extends MmsError {
  readonly code = 'AUTH_001';
  readonly statusCode = 401;
}

export class TokenExpiredError extends MmsError {
  readonly code = 'AUTH_002';
  readonly statusCode = 401;
}

export class InvalidTokenError extends MmsError {
  readonly code = 'AUTH_003';
  readonly statusCode = 401;
}

// =============================================================================
// Authorization Errors (403)
// =============================================================================

export class AuthorizationError extends MmsError {
  readonly code = 'AUTH_010';
  readonly statusCode = 403;
  readonly requiredPermission?: string;

  constructor(
    message: string,
    options?: {
      requiredPermission?: string;
      context?: Record<string, unknown>;
    }
  ) {
    super(message, options?.context);
    this.requiredPermission = options?.requiredPermission;
  }
}

export class DepotAccessError extends MmsError {
  readonly code = 'AUTH_011';
  readonly statusCode = 403;
  readonly depotId?: string;

  constructor(message: string, depotId?: string, context?: Record<string, unknown>) {
    super(message, context);
    this.depotId = depotId;
  }
}

// =============================================================================
// Not Found Errors (404)
// =============================================================================

export class NotFoundError extends MmsError {
  readonly code: string = 'BUS_010';
  readonly statusCode = 404;
  readonly entityType?: string;
  readonly entityId?: string;

  constructor(
    message: string,
    options?: {
      entityType?: string;
      entityId?: string;
      context?: Record<string, unknown>;
    }
  ) {
    super(message, options?.context);
    this.entityType = options?.entityType;
    this.entityId = options?.entityId;
  }
}

export class TrainNotFoundError extends NotFoundError {
  readonly code = 'BUS_011';

  constructor(trainId: string, context?: Record<string, unknown>) {
    super(`Train not found: ${trainId}`, {
      entityType: 'train',
      entityId: trainId,
      context,
    });
  }
}

export class PmScheduleNotFoundError extends NotFoundError {
  readonly code = 'BUS_012';

  constructor(scheduleId: string, context?: Record<string, unknown>) {
    super(`PM schedule not found: ${scheduleId}`, {
      entityType: 'pm_schedule',
      entityId: scheduleId,
      context,
    });
  }
}

// =============================================================================
// Conflict Errors (409)
// =============================================================================

export class ConflictError extends MmsError {
  readonly code = 'BUS_020';
  readonly statusCode = 409;
}

export class DuplicateError extends MmsError {
  readonly code = 'BUS_021';
  readonly statusCode = 409;
  readonly field?: string;
  readonly value?: unknown;

  constructor(
    message: string,
    options?: {
      field?: string;
      value?: unknown;
      context?: Record<string, unknown>;
    }
  ) {
    super(message, options?.context);
    this.field = options?.field;
    this.value = options?.value;
  }
}

export class MaximoLockError extends MmsError {
  readonly code = 'EXT_001';
  readonly statusCode = 409;
  readonly workOrderId?: string;
  readonly maximoStatus?: string;

  constructor(
    message: string,
    options?: {
      workOrderId?: string;
      maximoStatus?: string;
      context?: Record<string, unknown>;
    }
  ) {
    super(message, options?.context);
    this.workOrderId = options?.workOrderId;
    this.maximoStatus = options?.maximoStatus;
  }
}

export class TrackConflictError extends MmsError {
  readonly code = 'BUS_022';
  readonly statusCode = 409;
  readonly trackId?: string;
  readonly conflictingScheduleId?: string;

  constructor(
    message: string,
    options?: {
      trackId?: string;
      conflictingScheduleId?: string;
      context?: Record<string, unknown>;
    }
  ) {
    super(message, options?.context);
    this.trackId = options?.trackId;
    this.conflictingScheduleId = options?.conflictingScheduleId;
  }
}

// =============================================================================
// Business Logic Errors (422)
// =============================================================================

export class BusinessRuleError extends MmsError {
  readonly code = 'BUS_030';
  readonly statusCode = 422;
  readonly rule?: string;

  constructor(
    message: string,
    options?: {
      rule?: string;
      context?: Record<string, unknown>;
    }
  ) {
    super(message, options?.context);
    this.rule = options?.rule;
  }
}

export class ComplianceWindowError extends MmsError {
  readonly code = 'BUS_031';
  readonly statusCode = 422;
  readonly windowStart?: Date;
  readonly windowEnd?: Date;
  readonly targetDate?: Date;

  constructor(
    message: string,
    options?: {
      windowStart?: Date;
      windowEnd?: Date;
      targetDate?: Date;
      context?: Record<string, unknown>;
    }
  ) {
    super(message, options?.context);
    this.windowStart = options?.windowStart;
    this.windowEnd = options?.windowEnd;
    this.targetDate = options?.targetDate;
  }
}

export class MaterialConstraintError extends MmsError {
  readonly code = 'BUS_032';
  readonly statusCode = 422;
  readonly partNumber?: string;
  readonly requiredQuantity?: number;
  readonly availableQuantity?: number;

  constructor(
    message: string,
    options?: {
      partNumber?: string;
      requiredQuantity?: number;
      availableQuantity?: number;
      context?: Record<string, unknown>;
    }
  ) {
    super(message, options?.context);
    this.partNumber = options?.partNumber;
    this.requiredQuantity = options?.requiredQuantity;
    this.availableQuantity = options?.availableQuantity;
  }
}

export class ServiceDemandViolationError extends MmsError {
  readonly code = 'BUS_033';
  readonly statusCode = 422;
  readonly fleetId?: string;
  readonly requiredTrains?: number;
  readonly availableTrains?: number;

  constructor(
    message: string,
    options?: {
      fleetId?: string;
      requiredTrains?: number;
      availableTrains?: number;
      context?: Record<string, unknown>;
    }
  ) {
    super(message, options?.context);
    this.fleetId = options?.fleetId;
    this.requiredTrains = options?.requiredTrains;
    this.availableTrains = options?.availableTrains;
  }
}

// =============================================================================
// System Errors (500)
// =============================================================================

export class SystemError extends MmsError {
  readonly code = 'SYS_001';
  readonly statusCode = 500;
  readonly isOperational = false;
}

export class DatabaseError extends MmsError {
  readonly code = 'SYS_002';
  readonly statusCode = 500;
  readonly isOperational = false;
}

export class RedisError extends MmsError {
  readonly code = 'SYS_003';
  readonly statusCode = 500;
  readonly isOperational = false;
}

export class QueueError extends MmsError {
  readonly code = 'SYS_004';
  readonly statusCode = 500;
  readonly queueName?: string;
  readonly jobId?: string;

  constructor(
    message: string,
    options?: {
      queueName?: string;
      jobId?: string;
      context?: Record<string, unknown>;
    }
  ) {
    super(message, options?.context);
    this.queueName = options?.queueName;
    this.jobId = options?.jobId;
  }
}

// =============================================================================
// External System Errors (502, 503, 504)
// =============================================================================

export class ExternalServiceError extends MmsError {
  readonly code: string = 'EXT_010';
  readonly statusCode = 502;
  readonly service?: string;

  constructor(
    message: string,
    options?: {
      service?: string;
      context?: Record<string, unknown>;
    }
  ) {
    super(message, options?.context);
    this.service = options?.service;
  }
}

export class MaximoConnectionError extends ExternalServiceError {
  readonly code = 'EXT_011';

  constructor(message: string, context?: Record<string, unknown>) {
    super(message, { service: 'Maximo', context });
  }
}

export class ServiceUnavailableError extends MmsError {
  readonly code = 'SYS_010';
  readonly statusCode = 503;
  readonly retryAfter?: number;

  constructor(
    message: string,
    options?: {
      retryAfter?: number;
      context?: Record<string, unknown>;
    }
  ) {
    super(message, options?.context);
    this.retryAfter = options?.retryAfter;
  }
}

export class TimeoutError extends MmsError {
  readonly code = 'SYS_011';
  readonly statusCode = 504;
  readonly operation?: string;
  readonly timeoutMs?: number;

  constructor(
    message: string,
    options?: {
      operation?: string;
      timeoutMs?: number;
      context?: Record<string, unknown>;
    }
  ) {
    super(message, options?.context);
    this.operation = options?.operation;
    this.timeoutMs = options?.timeoutMs;
  }
}

// =============================================================================
// Error Utilities
// =============================================================================

/**
 * Type guard to check if an error is an MmsError
 */
export function isMmsError(error: unknown): error is MmsError {
  return error instanceof MmsError;
}

/**
 * Convert unknown error to MmsError
 */
export function toMmsError(error: unknown): MmsError {
  if (isMmsError(error)) {
    return error;
  }

  if (error instanceof Error) {
    return new SystemError(error.message, {
      originalError: error.name,
      stack: error.stack,
    });
  }

  return new SystemError(String(error));
}

/**
 * Error code registry for reference
 */
export const ERROR_CODES = {
  // Validation
  BUS_001: 'Validation error',
  FILE_001: 'CSV validation error',
  FILE_002: 'File operation error',
  ROW_001: 'Row validation error',

  // Auth
  AUTH_001: 'Authentication required',
  AUTH_002: 'Token expired',
  AUTH_003: 'Invalid token',
  AUTH_010: 'Authorization denied',
  AUTH_011: 'Depot access denied',

  // Not Found
  BUS_010: 'Resource not found',
  BUS_011: 'Train not found',
  BUS_012: 'PM schedule not found',

  // Conflicts
  BUS_020: 'Resource conflict',
  BUS_021: 'Duplicate resource',
  BUS_022: 'Track conflict',
  EXT_001: 'Maximo lock conflict',

  // Business Rules
  BUS_030: 'Business rule violation',
  BUS_031: 'Compliance window violation',
  BUS_032: 'Material constraint violation',
  BUS_033: 'Service demand violation',

  // System
  SYS_001: 'Internal system error',
  SYS_002: 'Database error',
  SYS_003: 'Redis error',
  SYS_004: 'Queue error',
  SYS_010: 'Service unavailable',
  SYS_011: 'Operation timeout',

  // External
  EXT_010: 'External service error',
  EXT_011: 'Maximo connection error',
} as const;

