/**
 * MMS OpenTelemetry Tracing Configuration
 *
 * Provides distributed tracing for all MMS services.
 * Integrates with Pino logging for correlated trace context.
 *
 * Features:
 * - Automatic span context propagation
 * - Span attribute helpers for domain-specific data
 * - Integration with existing Pino logger
 * - Configurable exporters (OTLP, Jaeger, Console)
 *
 * @see specs/004-domain-services.md - All services emit OpenTelemetry traces
 */

import {
  trace,
  context,
  SpanStatusCode,
  SpanKind,
  type Span,
  type Tracer,
  type Context,
  type SpanOptions,
  type Attributes,
} from '@opentelemetry/api';
import {
  SEMRESATTRS_SERVICE_NAME,
  SEMRESATTRS_SERVICE_VERSION,
  SEMRESATTRS_DEPLOYMENT_ENVIRONMENT,
} from '@opentelemetry/semantic-conventions';

const SERVICE_NAME = process.env['SERVICE_NAME'] ?? 'mms';
const SERVICE_VERSION = process.env['SERVICE_VERSION'] ?? '0.1.0';
const ENVIRONMENT = process.env['NODE_ENV'] ?? 'development';

/**
 * Domain-specific span attributes for MMS
 */
export const MmsAttributes = {
  // Train attributes
  TRAIN_ID: 'mms.train.id',
  TRAIN_NUMBER: 'mms.train.number',
  FLEET_ID: 'mms.fleet.id',

  // PM attributes
  PM_SCHEDULE_ID: 'mms.pm.schedule_id',
  PM_TYPE_CODE: 'mms.pm.type_code',
  PM_STATUS: 'mms.pm.status',

  // Depot attributes
  DEPOT_ID: 'mms.depot.id',
  DEPOT_CODE: 'mms.depot.code',

  // Mileage attributes
  MILEAGE_KM: 'mms.mileage.km',
  DAILY_KM: 'mms.mileage.daily_km',

  // Ingestion attributes
  INGESTION_FILE: 'mms.ingestion.file',
  INGESTION_JOB_ID: 'mms.ingestion.job_id',
  INGESTION_RECORD_COUNT: 'mms.ingestion.record_count',
  INGESTION_RECORDS: 'mms.ingestion.records',
  INGESTION_VALID: 'mms.ingestion.valid',
  INGESTION_INVALID: 'mms.ingestion.invalid',

  // Optimizer attributes
  OPTIMIZER_JOB_ID: 'mms.optimizer.job_id',
  OPTIMIZER_SOLVER: 'mms.optimizer.solver',
  OPTIMIZER_SOLVE_TIME_MS: 'mms.optimizer.solve_time_ms',
  OPTIMIZER_OBJECTIVE: 'mms.optimizer.objective',
  OPTIMIZER_STATUS: 'mms.optimizer.status',

  // Baseline attributes
  BASELINE_ID: 'mms.baseline.id',
  BASELINE_VERSION: 'mms.baseline.version',

  // Scenario attributes
  SCENARIO_ID: 'mms.scenario.id',
  SCENARIO_NAME: 'mms.scenario.name',

  // Queue attributes
  QUEUE_NAME: 'mms.queue.name',
  JOB_ID: 'mms.job.id',
  JOB_ATTEMPT: 'mms.job.attempt',

  // User attributes
  USER_ID: 'mms.user.id',
  USER_EMAIL: 'mms.user.email',

  // Database attributes
  DB_OPERATION: 'mms.db.operation',
  DB_TABLE: 'mms.db.table',
  DB_ROWS_AFFECTED: 'mms.db.rows_affected',

  // Error attributes
  ERROR_CODE: 'mms.error.code',
  ERROR_TYPE: 'mms.error.type',
} as const;

/**
 * Get the configured tracer for a service
 */
export function getTracer(serviceName?: string): Tracer {
  return trace.getTracer(serviceName ?? SERVICE_NAME, SERVICE_VERSION);
}

/**
 * Get service-level attributes for span context
 */
export function getServiceAttributes(): Attributes {
  return {
    [SEMRESATTRS_SERVICE_NAME]: SERVICE_NAME,
    [SEMRESATTRS_SERVICE_VERSION]: SERVICE_VERSION,
    [SEMRESATTRS_DEPLOYMENT_ENVIRONMENT]: ENVIRONMENT,
  };
}

/**
 * Start a new span for an operation
 */
export function startSpan(
  name: string,
  options?: SpanOptions & { tracer?: Tracer }
): Span {
  const tracer = options?.tracer ?? getTracer();
  return tracer.startSpan(name, {
    ...options,
    attributes: {
      ...getServiceAttributes(),
      ...options?.attributes,
    },
  });
}

/**
 * Execute a function within a traced span
 *
 * Automatically records errors and sets span status.
 *
 * @example
 * const result = await withSpan('processRecord', async (span) => {
 *   span.setAttribute(MmsAttributes.TRAIN_ID, trainId);
 *   return processRecord(record);
 * });
 */
export async function withSpan<T>(
  name: string,
  fn: (span: Span) => Promise<T>,
  options?: SpanOptions & { tracer?: Tracer }
): Promise<T> {
  const tracer = options?.tracer ?? getTracer();
  const span = tracer.startSpan(name, {
    kind: SpanKind.INTERNAL,
    ...options,
    attributes: {
      ...getServiceAttributes(),
      ...options?.attributes,
    },
  });

  const ctx = trace.setSpan(context.active(), span);

  try {
    const result = await context.with(ctx, () => fn(span));
    span.setStatus({ code: SpanStatusCode.OK });
    return result;
  } catch (error) {
    recordSpanError(span, error);
    throw error;
  } finally {
    span.end();
  }
}

/**
 * Synchronous version of withSpan
 */
export function withSpanSync<T>(
  name: string,
  fn: (span: Span) => T,
  options?: SpanOptions & { tracer?: Tracer }
): T {
  const tracer = options?.tracer ?? getTracer();
  const span = tracer.startSpan(name, {
    kind: SpanKind.INTERNAL,
    ...options,
    attributes: {
      ...getServiceAttributes(),
      ...options?.attributes,
    },
  });

  const ctx = trace.setSpan(context.active(), span);

  try {
    const result = context.with(ctx, () => fn(span));
    span.setStatus({ code: SpanStatusCode.OK });
    return result;
  } catch (error) {
    recordSpanError(span, error);
    throw error;
  } finally {
    span.end();
  }
}

/**
 * Record an error on a span
 */
export function recordSpanError(span: Span, error: unknown): void {
  span.setStatus({
    code: SpanStatusCode.ERROR,
    message: error instanceof Error ? error.message : String(error),
  });

  if (error instanceof Error) {
    span.recordException(error);

    // Add MMS error attributes if available
    const mmsError = error as Error & { code?: string; statusCode?: number };
    if (mmsError.code) {
      span.setAttribute(MmsAttributes.ERROR_CODE, mmsError.code);
    }
    if (mmsError.statusCode) {
      span.setAttribute('http.status_code', mmsError.statusCode);
    }
    span.setAttribute(MmsAttributes.ERROR_TYPE, error.name);
  }
}

/**
 * Add an event to the current span
 */
export function addSpanEvent(
  name: string,
  attributes?: Attributes,
  span?: Span
): void {
  const currentSpan = span ?? trace.getActiveSpan();
  currentSpan?.addEvent(name, attributes);
}

/**
 * Get the current active span
 */
export function getActiveSpan(): Span | undefined {
  return trace.getActiveSpan();
}

/**
 * Get the current trace ID (for correlation with logs)
 */
export function getTraceId(): string | undefined {
  return getActiveSpan()?.spanContext().traceId;
}

/**
 * Get the current span ID
 */
export function getSpanId(): string | undefined {
  return getActiveSpan()?.spanContext().spanId;
}

/**
 * Create a trace context object for logging
 */
export function getTraceContext(): { traceId?: string; spanId?: string } {
  const span = getActiveSpan();
  if (!span) return {};

  const ctx = span.spanContext();
  return {
    traceId: ctx.traceId,
    spanId: ctx.spanId,
  };
}

/**
 * Execute a function within the context of an existing span
 */
export async function withContext<T>(
  ctx: Context,
  fn: () => Promise<T>
): Promise<T> {
  return context.with(ctx, fn);
}

/**
 * Create a linked span (for async operations that continue from another trace)
 */
export function createLinkedSpan(
  name: string,
  parentSpan: Span,
  options?: SpanOptions
): Span {
  const tracer = getTracer();
  return tracer.startSpan(name, {
    ...options,
    links: [
      ...(options?.links ?? []),
      { context: parentSpan.spanContext() },
    ],
    attributes: {
      ...getServiceAttributes(),
      ...options?.attributes,
    },
  });
}

/**
 * Span kind constants for convenience
 */
export { SpanKind, SpanStatusCode } from '@opentelemetry/api';

/**
 * Type exports
 */
export type { Span, Tracer, Context, SpanOptions, Attributes };

/**
 * MMS Prometheus Metrics
 *
 * Application metrics for monitoring and alerting.
 * Exposed via /metrics endpoint for Prometheus scraping.
 *
 * Metric types:
 * - Counter: Monotonically increasing values (requests, errors)
 * - Gauge: Point-in-time values (active jobs, queue depth)
 * - Histogram: Distribution of values (request duration, solve time)
 *
 * @see specs/004-backend-specification.md Section 4.14
 */

import { Registry, Counter, Gauge, Histogram, collectDefaultMetrics } from 'prom-client';

// =============================================================================
// Registry Setup
// =============================================================================

export const registry = new Registry();

// Add default Node.js metrics (CPU, memory, event loop, etc.)
collectDefaultMetrics({
  register: registry,
  prefix: 'mms_',
});

// =============================================================================
// HTTP Metrics
// =============================================================================

export const httpRequestsTotal = new Counter({
  name: 'mms_http_requests_total',
  help: 'Total number of HTTP requests',
  labelNames: ['method', 'path', 'status'] as const,
  registers: [registry],
});

export const httpRequestDuration = new Histogram({
  name: 'mms_http_request_duration_seconds',
  help: 'HTTP request duration in seconds',
  labelNames: ['method', 'path', 'status'] as const,
  buckets: [0.01, 0.05, 0.1, 0.25, 0.5, 1, 2.5, 5, 10],
  registers: [registry],
});

export const httpRequestsInFlight = new Gauge({
  name: 'mms_http_requests_in_flight',
  help: 'Number of HTTP requests currently being processed',
  labelNames: ['method'] as const,
  registers: [registry],
});

// =============================================================================
// PM Scheduling Metrics
// =============================================================================

export const pmScheduledTotal = new Counter({
  name: 'mms_pm_scheduled_total',
  help: 'Total number of PM events scheduled',
  labelNames: ['pm_code', 'fleet_id', 'status'] as const,
  registers: [registry],
});

export const pmComplianceWindowDays = new Histogram({
  name: 'mms_pm_compliance_window_days',
  help: 'Days between PM scheduling and compliance window end',
  labelNames: ['pm_code'] as const,
  buckets: [-14, -7, 0, 7, 14, 30, 60, 90],
  registers: [registry],
});

export const pmDeferredTotal = new Counter({
  name: 'mms_pm_deferred_total',
  help: 'Total number of PM events deferred',
  labelNames: ['pm_code', 'reason'] as const,
  registers: [registry],
});

// =============================================================================
// Optimizer Metrics
// =============================================================================

export const optimizerSolveSeconds = new Histogram({
  name: 'mms_optimizer_solve_seconds',
  help: 'Optimizer solve time in seconds',
  labelNames: ['solver_type', 'status'] as const,
  buckets: [0.1, 0.5, 1, 5, 10, 30, 60, 120],
  registers: [registry],
});

export const optimizerRunsTotal = new Counter({
  name: 'mms_optimizer_runs_total',
  help: 'Total number of optimizer runs',
  labelNames: ['solver_type', 'status'] as const,
  registers: [registry],
});

export const optimizerObjectiveValue = new Gauge({
  name: 'mms_optimizer_objective_value',
  help: 'Latest optimizer objective value',
  labelNames: ['solver_type'] as const,
  registers: [registry],
});

export const optimizerFallbacksTotal = new Counter({
  name: 'mms_optimizer_fallbacks_total',
  help: 'Number of times fallback solver was used',
  labelNames: ['reason'] as const,
  registers: [registry],
});

// =============================================================================
// Fleet Metrics
// =============================================================================

export const fleetMileageKm = new Gauge({
  name: 'mms_fleet_mileage_km',
  help: 'Current cumulative mileage per train',
  labelNames: ['train_id', 'fleet_id'] as const,
  registers: [registry],
});

export const fleetTrainStatus = new Gauge({
  name: 'mms_fleet_train_status',
  help: 'Train fitness status (1=FIT, 0.5=RESTRICTED, 0=GROUNDED)',
  labelNames: ['train_id', 'fleet_id', 'status'] as const,
  registers: [registry],
});

export const fleetAvailableTrains = new Gauge({
  name: 'mms_fleet_available_trains',
  help: 'Number of trains available for service',
  labelNames: ['fleet_id'] as const,
  registers: [registry],
});

// =============================================================================
// Drift Metrics
// =============================================================================

export const driftTrainsRequiringReplan = new Gauge({
  name: 'mms_drift_trains_requiring_replan',
  help: 'Number of trains requiring schedule replan due to drift',
  labelNames: ['baseline_id'] as const,
  registers: [registry],
});

export const driftMileagePercent = new Gauge({
  name: 'mms_drift_mileage_percent',
  help: 'Mileage drift percentage per train',
  labelNames: ['train_id', 'baseline_id'] as const,
  registers: [registry],
});

export const driftAnalysisTotal = new Counter({
  name: 'mms_drift_analysis_total',
  help: 'Total number of drift analyses performed',
  labelNames: ['result'] as const,
  registers: [registry],
});

// =============================================================================
// Queue Metrics
// =============================================================================

export const queueJobsTotal = new Counter({
  name: 'mms_queue_jobs_total',
  help: 'Total number of queue jobs processed',
  labelNames: ['queue', 'status'] as const,
  registers: [registry],
});

export const queueJobDuration = new Histogram({
  name: 'mms_queue_job_duration_seconds',
  help: 'Queue job processing duration in seconds',
  labelNames: ['queue', 'job_name'] as const,
  buckets: [0.1, 1, 5, 10, 30, 60, 300, 600],
  registers: [registry],
});

export const queueDepth = new Gauge({
  name: 'mms_queue_depth',
  help: 'Number of jobs waiting in queue',
  labelNames: ['queue', 'state'] as const,
  registers: [registry],
});

// =============================================================================
// Ingestion Metrics
// =============================================================================

export const ingestionFilesTotal = new Counter({
  name: 'mms_ingestion_files_total',
  help: 'Total number of files processed',
  labelNames: ['status'] as const,
  registers: [registry],
});

export const ingestionRowsTotal = new Counter({
  name: 'mms_ingestion_rows_total',
  help: 'Total number of rows processed',
  labelNames: ['status'] as const,
  registers: [registry],
});

export const ingestionAnomaliesTotal = new Counter({
  name: 'mms_ingestion_anomalies_total',
  help: 'Total number of anomalies detected',
  labelNames: ['type'] as const,
  registers: [registry],
});

// =============================================================================
// Man-hour Metrics
// =============================================================================

export const manhourUtilizationPercent = new Gauge({
  name: 'mms_manhour_utilization_percent',
  help: 'Man-hour utilization percentage per depot',
  labelNames: ['depot_id', 'period'] as const,
  registers: [registry],
});

export const manhourOverloadedPeriods = new Gauge({
  name: 'mms_manhour_overloaded_periods',
  help: 'Number of overloaded periods per depot',
  labelNames: ['depot_id'] as const,
  registers: [registry],
});

export const manhourAdjustmentsTotal = new Counter({
  name: 'mms_manhour_adjustments_total',
  help: 'Total number of man-hour adjustments made',
  labelNames: ['depot_id', 'strategy', 'status'] as const,
  registers: [registry],
});

// =============================================================================
// Database Metrics
// =============================================================================

export const dbQueryDuration = new Histogram({
  name: 'mms_db_query_duration_seconds',
  help: 'Database query duration in seconds',
  labelNames: ['operation', 'table'] as const,
  buckets: [0.001, 0.005, 0.01, 0.05, 0.1, 0.5, 1, 5],
  registers: [registry],
});

export const dbConnectionPoolSize = new Gauge({
  name: 'mms_db_connection_pool_size',
  help: 'Database connection pool size',
  labelNames: ['state'] as const,
  registers: [registry],
});

export const dbErrorsTotal = new Counter({
  name: 'mms_db_errors_total',
  help: 'Total number of database errors',
  labelNames: ['operation', 'error_code'] as const,
  registers: [registry],
});

// =============================================================================
// Utility Functions
// =============================================================================

/**
 * Get metrics output for Prometheus scraping
 */
export async function getMetrics(): Promise<string> {
  return registry.metrics();
}

/**
 * Get content type for metrics response
 */
export function getMetricsContentType(): string {
  return registry.contentType;
}

/**
 * Reset all metrics (useful for testing)
 */
export function resetMetrics(): void {
  registry.resetMetrics();
}

/**
 * HTTP middleware helper - measure request duration
 */
export function measureHttpRequest(
  method: string,
  path: string,
  status: number,
  durationMs: number
): void {
  const labels = { method, path, status: String(status) };
  httpRequestsTotal.inc(labels);
  httpRequestDuration.observe(labels, durationMs / 1000);
}

/**
 * Queue job helper - record job completion
 */
export function recordQueueJob(
  queue: string,
  jobName: string,
  status: 'completed' | 'failed',
  durationMs: number
): void {
  queueJobsTotal.inc({ queue, status });
  queueJobDuration.observe({ queue, job_name: jobName }, durationMs / 1000);
}

/**
 * Optimizer helper - record solve completion
 */
export function recordOptimizerRun(
  solverType: 'cpsat' | 'fallback',
  status: 'optimal' | 'feasible' | 'infeasible' | 'timeout' | 'error',
  durationMs: number,
  objective?: number
): void {
  optimizerRunsTotal.inc({ solver_type: solverType, status });
  optimizerSolveSeconds.observe({ solver_type: solverType, status }, durationMs / 1000);
  if (objective !== undefined) {
    optimizerObjectiveValue.set({ solver_type: solverType }, objective);
  }
}

// =============================================================================
// Ingestion Helpers
// =============================================================================

/**
 * Ingestion metrics object for easy access
 */
export const ingestionMetrics = {
  filesReceived: new Counter({
    name: 'mms_ingestion_files_received_total',
    help: 'Total number of files received for ingestion',
    registers: [registry],
  }),
  recordsProcessed: new Counter({
    name: 'mms_ingestion_records_processed_total',
    help: 'Total number of records processed',
    registers: [registry],
  }),
  processingDuration: new Histogram({
    name: 'mms_ingestion_processing_duration_seconds',
    help: 'Ingestion processing duration in seconds',
    labelNames: ['status'] as const,
    buckets: [0.1, 0.5, 1, 5, 10, 30, 60, 120, 300],
    registers: [registry],
  }),
};

/**
 * Record ingestion completion
 */
export function recordIngestionComplete(
  status: 'SUCCESS' | 'PARTIAL' | 'FAILED',
  durationMs: number
): void {
  ingestionFilesTotal.inc({ status: status.toLowerCase() });
  ingestionMetrics.processingDuration.observe({ status: status.toLowerCase() }, durationMs / 1000);
}

/**
 * Record ingestion anomaly
 */
export function recordIngestionAnomaly(type: string): void {
  ingestionAnomaliesTotal.inc({ type });
}

