/**
 * MMS Base Service
 *
 * Abstract base class for all domain services in the MMS system.
 * Provides consistent patterns for:
 * - OpenTelemetry distributed tracing
 * - Structured logging with Pino
 * - Database transaction management
 * - Error handling and propagation
 *
 * All domain services (Ingestion, Fleet, PM Scheduler, etc.) extend this base.
 *
 * @see specs/004-domain-services.md
 */

import type { Logger } from 'pino';
import type { Span, Attributes } from '@opentelemetry/api';
import { createChildLogger, logError as pinoLogError } from '../logging/logger';
import { db, withTransaction, type Transaction, type Database } from '../db/connection';
import {
  withSpan,
  withSpanSync,
  getTracer,
  getTraceContext,
  recordSpanError,
  addSpanEvent,
  MmsAttributes,
  SpanKind,
  type Tracer,
} from '../tracing';
import { MmsError, toMmsError } from '../errors';

/**
 * Service configuration options
 */
export interface ServiceConfig {
  /** Service name for tracing and logging */
  name: string;
  /** Service version */
  version?: string;
  /** Additional context for all logs and spans */
  context?: Record<string, unknown>;
}

/**
 * Operation result wrapper for consistent return types
 */
export interface OperationResult<T> {
  success: boolean;
  data?: T;
  error?: MmsError;
  durationMs: number;
}

/**
 * Base service class for all MMS domain services
 *
 * @example
 * ```typescript
 * class FleetService extends BaseService {
 *   constructor() {
 *     super({ name: 'fleet-service' });
 *   }
 *
 *   async getTrains(fleetId: string): Promise<Train[]> {
 *     return this.traced('getTrains', async (span) => {
 *       span.setAttribute(MmsAttributes.FLEET_ID, fleetId);
 *       return this.db.query.trains.findMany({
 *         where: eq(trains.fleetId, fleetId)
 *       });
 *     });
 *   }
 * }
 * ```
 */
export abstract class BaseService {
  protected readonly serviceName: string;
  protected readonly log: Logger;
  protected readonly tracer: Tracer;
  protected readonly db: Database;

  constructor(config: ServiceConfig) {
    this.serviceName = config.name;
    this.log = createChildLogger({
      service: config.name,
      version: config.version ?? '0.1.0',
      ...config.context,
    });
    this.tracer = getTracer(config.name);
    this.db = db;
  }

  /**
   * Execute an async operation with tracing
   *
   * Automatically creates a span, records errors, and measures duration.
   * Propagates trace context for distributed tracing.
   *
   * @param operationName - Name of the operation (becomes span name)
   * @param fn - Async function to execute
   * @param attributes - Optional span attributes
   */
  protected async traced<T>(
    operationName: string,
    fn: (span: Span) => Promise<T>,
    attributes?: Attributes
  ): Promise<T> {
    const spanName = `${this.serviceName}.${operationName}`;

    return withSpan(
      spanName,
      async (span) => {
        // Add operation start log
        this.log.debug(
          { operation: operationName, ...getTraceContext() },
          `Starting ${operationName}`
        );

        const startTime = Date.now();

        try {
          const result = await fn(span);

          // Add operation complete log
          const durationMs = Date.now() - startTime;
          this.log.info(
            { operation: operationName, durationMs, ...getTraceContext() },
            `Completed ${operationName} in ${durationMs}ms`
          );

          return result;
        } catch (error) {
          const durationMs = Date.now() - startTime;
          const mmsError = toMmsError(error);

          this.log.error(
            {
              operation: operationName,
              durationMs,
              error: mmsError.toJSON(),
              ...getTraceContext(),
            },
            `Failed ${operationName}: ${mmsError.message}`
          );

          throw mmsError;
        }
      },
      {
        kind: SpanKind.INTERNAL,
        tracer: this.tracer,
        attributes: {
          'service.name': this.serviceName,
          'operation.name': operationName,
          ...attributes,
        },
      }
    );
  }

  /**
   * Execute a sync operation with tracing
   */
  protected tracedSync<T>(
    operationName: string,
    fn: (span: Span) => T,
    attributes?: Attributes
  ): T {
    const spanName = `${this.serviceName}.${operationName}`;

    return withSpanSync(
      spanName,
      (span) => {
        const startTime = Date.now();

        try {
          const result = fn(span);

          const durationMs = Date.now() - startTime;
          this.log.debug(
            { operation: operationName, durationMs, ...getTraceContext() },
            `Completed ${operationName} in ${durationMs}ms`
          );

          return result;
        } catch (error) {
          const durationMs = Date.now() - startTime;
          const mmsError = toMmsError(error);

          this.log.error(
            {
              operation: operationName,
              durationMs,
              error: mmsError.toJSON(),
              ...getTraceContext(),
            },
            `Failed ${operationName}: ${mmsError.message}`
          );

          throw mmsError;
        }
      },
      {
        kind: SpanKind.INTERNAL,
        tracer: this.tracer,
        attributes: {
          'service.name': this.serviceName,
          'operation.name': operationName,
          ...attributes,
        },
      }
    );
  }

  /**
   * Execute a database transaction with tracing
   *
   * Automatically commits on success, rolls back on error.
   * Creates a child span for the transaction.
   *
   * @param operationName - Name of the operation
   * @param fn - Function to execute within the transaction
   */
  protected async inTransaction<T>(
    operationName: string,
    fn: (tx: Transaction, span: Span) => Promise<T>
  ): Promise<T> {
    return this.traced(
      `${operationName}.transaction`,
      async (span) => {
        span.setAttribute(MmsAttributes.DB_OPERATION, 'transaction');
        addSpanEvent('transaction.begin', undefined, span);

        try {
          const result = await withTransaction(async (tx) => fn(tx, span));
          addSpanEvent('transaction.commit', undefined, span);
          return result;
        } catch (error) {
          addSpanEvent('transaction.rollback', undefined, span);
          throw error;
        }
      },
      { [MmsAttributes.DB_OPERATION]: 'transaction' }
    );
  }

  /**
   * Wrap an operation result with timing and error info
   */
  protected async safeExecute<T>(
    operationName: string,
    fn: () => Promise<T>
  ): Promise<OperationResult<T>> {
    const startTime = Date.now();

    try {
      const data = await fn();
      return {
        success: true,
        data,
        durationMs: Date.now() - startTime,
      };
    } catch (error) {
      const mmsError = toMmsError(error);
      return {
        success: false,
        error: mmsError,
        durationMs: Date.now() - startTime,
      };
    }
  }

  /**
   * Record a domain event on the current span
   */
  protected recordEvent(
    name: string,
    attributes?: Attributes,
    span?: Span
  ): void {
    addSpanEvent(name, attributes, span);
    this.log.debug({ event: name, ...attributes }, `Event: ${name}`);
  }

  /**
   * Record an error in logs and traces
   */
  protected recordError(error: Error | unknown, span?: Span): void {
    const mmsError = toMmsError(error);
    pinoLogError(this.log, mmsError instanceof Error ? mmsError : new Error(String(error)));
    if (span) {
      recordSpanError(span, error);
    }
  }

  /**
   * Create a child logger with additional context
   */
  protected childLogger(context: Record<string, unknown>): Logger {
    return this.log.child(context);
  }
}

/**
 * Export MmsAttributes for use in service implementations
 */
export { MmsAttributes };

/**
 * Re-export types for convenience
 */
export type { Span, Attributes, Logger, Transaction, Database };

/**
 * MMS Services Module
 *
 * Exports base service infrastructure for domain services.
 */

export { BaseService, MmsAttributes } from './base';
export type {
  ServiceConfig,
  OperationResult,
  Span,
  Attributes,
  Logger,
  Transaction,
  Database,
} from './base';

/**
 * MMS Zod Validation Schemas
 *
 * Centralized validation schemas for API requests, CSV imports, and IPC.
 * All schemas include helpful error messages for better DX.
 *
 * @see specs/005-api-specification.md
 */

import { z } from 'zod';

// =============================================================================
// Primitive Schemas
// =============================================================================

/** UUID v4 validation */
export const uuidSchema = z.string().uuid('Invalid UUID format');

/** ISO date string (YYYY-MM-DD) */
export const dateStringSchema = z
  .string()
  .regex(/^\d{4}-\d{2}-\d{2}$/, 'Date must be in YYYY-MM-DD format');

/** ISO datetime string */
export const datetimeStringSchema = z.string().datetime('Invalid ISO datetime format');

/** Positive integer */
export const positiveIntSchema = z.number().int().positive();

/** Non-negative integer */
export const nonNegativeIntSchema = z.number().int().nonnegative();

/** Percentage (0-100) */
export const percentageSchema = z.number().min(0).max(100);

/** Mileage value (km) */
export const mileageKmSchema = z
  .number()
  .int()
  .nonnegative()
  .max(10_000_000, 'Mileage cannot exceed 10 million km');

// =============================================================================
// Enum Schemas
// =============================================================================

export const fitnessStatusSchema = z.enum(['FIT', 'RESTRICTED', 'GROUNDED']);

export const pmStatusSchema = z.enum([
  'SCHEDULED',
  'IN_PROGRESS',
  'COMPLETED',
  'CANCELLED',
  'DEFERRED',
]);

export const trackTypeSchema = z.enum([
  'HEAVY_MAINTENANCE',
  'LIGHT_MAINTENANCE',
  'INSPECTION',
  'STABLING',
  'WASHING',
  'OVERHAUL',
]);

export const dayTypeSchema = z.enum(['WEEKDAY', 'SATURDAY', 'SUNDAY', 'HOLIDAY']);

export const validationStatusSchema = z.enum(['VALID', 'ANOMALY', 'PENDING', 'REJECTED']);

export const reservationTypeSchema = z.enum(['SOFT', 'HARD']);

export const adjustmentTypeSchema = z.enum([
  'ADVANCE_PM',
  'DEFER_PM',
  'ADD_OVERTIME',
  'CROSS_DEPOT',
  'ADD_CONTRACTOR',
  'MANUAL_REVIEW',
]);

export const baselineStatusSchema = z.enum(['DRAFT', 'PUBLISHED', 'SUPERSEDED']);

export const scenarioStatusSchema = z.enum(['ACTIVE', 'PROMOTED', 'EXPIRED', 'DELETED']);

// =============================================================================
// Pagination & Filtering
// =============================================================================

export const paginationSchema = z.object({
  page: z.coerce.number().int().positive().default(1),
  pageSize: z.coerce.number().int().min(1).max(100).default(20),
  sort: z.string().optional(),
  sortDir: z.enum(['asc', 'desc']).default('asc'),
});

export type Pagination = z.infer<typeof paginationSchema>;

export const dateRangeSchema = z
  .object({
    startDate: dateStringSchema,
    endDate: dateStringSchema,
  })
  .refine(
    (data) => new Date(data.startDate) <= new Date(data.endDate),
    'Start date must be before or equal to end date'
  );

// =============================================================================
// Train Schemas
// =============================================================================

export const trainSchema = z.object({
  id: uuidSchema,
  trainNumber: z.string().min(1).max(20),
  fleetId: uuidSchema,
  currentMileageKm: mileageKmSchema,
  fitnessStatus: fitnessStatusSchema,
  targetMileageKm: mileageKmSchema.optional(),
  displayColor: z.string().regex(/^#[0-9A-Fa-f]{6}$/).optional(),
});

export const trainUpdateSchema = z.object({
  fitnessStatus: fitnessStatusSchema.optional(),
  targetMileageKm: mileageKmSchema.optional(),
  displayColor: z.string().regex(/^#[0-9A-Fa-f]{6}$/).optional(),
  restrictions: z.array(z.string()).optional(),
});

export type Train = z.infer<typeof trainSchema>;
export type TrainUpdate = z.infer<typeof trainUpdateSchema>;

// =============================================================================
// PM Schedule Schemas
// =============================================================================

export const pmScheduleSchema = z.object({
  id: uuidSchema,
  trainId: uuidSchema,
  pmTypeId: uuidSchema,
  targetDate: dateStringSchema,
  status: pmStatusSchema,
  constraintWindowStart: dateStringSchema.optional(),
  constraintWindowEnd: dateStringSchema.optional(),
  assignedDepotId: uuidSchema.optional(),
  assignedTrackId: uuidSchema.optional(),
  estimatedHours: z.number().positive().optional(),
  isLocked: z.boolean().default(false),
  maximoStatus: z.string().optional(),
});

export const pmScheduleCreateSchema = z.object({
  trainId: uuidSchema,
  pmTypeId: uuidSchema,
  targetDate: dateStringSchema,
  assignedDepotId: uuidSchema.optional(),
  assignedTrackId: uuidSchema.optional(),
  notes: z.string().max(1000).optional(),
});

export const pmScheduleMoveSchema = z.object({
  newTargetDate: dateStringSchema,
  reason: z.string().min(10, 'Reason must be at least 10 characters').max(500),
});

export type PmSchedule = z.infer<typeof pmScheduleSchema>;
export type PmScheduleCreate = z.infer<typeof pmScheduleCreateSchema>;
export type PmScheduleMove = z.infer<typeof pmScheduleMoveSchema>;

// =============================================================================
// Mileage Schemas
// =============================================================================

export const mileageReadingSchema = z.object({
  trainId: uuidSchema,
  readingDate: dateStringSchema,
  rawReadingKm: mileageKmSchema,
  adjustedReadingKm: mileageKmSchema.optional(),
  dailyKm: z.number().int().optional(),
  validationStatus: validationStatusSchema.default('PENDING'),
});

export const meterEventSchema = z.object({
  trainId: uuidSchema,
  eventDate: dateStringSchema,
  eventType: z.enum(['RESET', 'REPLACEMENT', 'CALIBRATION', 'CORRECTION']),
  oldReadingKm: mileageKmSchema,
  newReadingKm: mileageKmSchema,
  adjustmentKm: z.number().int(),
  notes: z.string().max(500).optional(),
});

export type MileageReading = z.infer<typeof mileageReadingSchema>;
export type MeterEvent = z.infer<typeof meterEventSchema>;

// =============================================================================
// CSV Import Schemas
// =============================================================================

/** Mileage CSV row validation */
export const mileageCsvRowSchema = z.object({
  train_number: z.string().min(1, 'Train number required'),
  reading_date: dateStringSchema,
  odometer_km: z
    .string()
    .transform((val) => parseInt(val, 10))
    .pipe(mileageKmSchema),
});

/** Fleet roster CSV row validation */
export const fleetRosterCsvRowSchema = z.object({
  train_number: z.string().min(1),
  fleet_code: z.string().min(1),
  current_mileage_km: z
    .string()
    .transform((val) => parseInt(val, 10))
    .pipe(mileageKmSchema),
  commissioning_date: dateStringSchema.optional(),
  fitness_status: fitnessStatusSchema.optional(),
});

/** PM history CSV row validation */
export const pmHistoryCsvRowSchema = z.object({
  train_number: z.string().min(1),
  pm_code: z.string().min(1),
  completion_date: dateStringSchema,
  completion_mileage_km: z
    .string()
    .transform((val) => parseInt(val, 10))
    .pipe(mileageKmSchema)
    .optional(),
  work_order_id: z.string().optional(),
});

export type MileageCsvRow = z.infer<typeof mileageCsvRowSchema>;
export type FleetRosterCsvRow = z.infer<typeof fleetRosterCsvRowSchema>;
export type PmHistoryCsvRow = z.infer<typeof pmHistoryCsvRowSchema>;

// =============================================================================
// Optimizer IPC Schemas
// =============================================================================

/** Optimizer input message */
export const optimizerInputSchema = z.object({
  date: dateStringSchema,
  fleetId: uuidSchema,
  trains: z.array(
    z.object({
      id: uuidSchema,
      trainNumber: z.string(),
      currentMileageKm: mileageKmSchema,
      targetMileageKm: mileageKmSchema.optional(),
      fitnessStatus: fitnessStatusSchema,
      compatibleRoutes: z.array(uuidSchema),
    })
  ),
  routes: z.array(
    z.object({
      id: uuidSchema,
      routeCode: z.string(),
      expectedKmPerDay: positiveIntSchema,
      requiredTrains: positiveIntSchema,
    })
  ),
  constraints: z
    .object({
      unavailableTrains: z.array(uuidSchema).optional(),
      preferredAssignments: z.record(uuidSchema, uuidSchema).optional(),
      minServiceTrains: z.record(uuidSchema, positiveIntSchema).optional(),
    })
    .optional(),
  config: z
    .object({
      timeoutMs: positiveIntSchema.default(30000),
      mileageBalanceWeight: positiveIntSchema.default(100),
      preferenceWeight: positiveIntSchema.default(50),
    })
    .optional(),
});

/** Optimizer output message types */
export const optimizerProgressSchema = z.object({
  type: z.literal('PROGRESS'),
  percent: percentageSchema,
  objective: z.number().optional(),
  feasible: z.boolean().optional(),
});

export const optimizerHeartbeatSchema = z.object({
  type: z.literal('HEARTBEAT'),
  timestamp: datetimeStringSchema,
});

export const optimizerErrorSchema = z.object({
  type: z.literal('ERROR'),
  code: z.string(),
  message: z.string(),
});

export const optimizerResultSchema = z.object({
  type: z.literal('RESULT'),
  status: z.enum(['OPTIMAL', 'FEASIBLE', 'INFEASIBLE', 'TIMEOUT', 'ERROR']),
  objective: z.number().optional(),
  assignments: z.array(
    z.object({
      trainId: uuidSchema,
      routeId: uuidSchema.nullable(),
      explanation: z.string().optional(),
    })
  ),
  solveTimeMs: positiveIntSchema,
  iterations: positiveIntSchema.optional(),
});

export const optimizerOutputSchema = z.union([
  optimizerProgressSchema,
  optimizerHeartbeatSchema,
  optimizerErrorSchema,
  optimizerResultSchema,
]);

export type OptimizerInput = z.infer<typeof optimizerInputSchema>;
export type OptimizerProgress = z.infer<typeof optimizerProgressSchema>;
export type OptimizerHeartbeat = z.infer<typeof optimizerHeartbeatSchema>;
export type OptimizerError = z.infer<typeof optimizerErrorSchema>;
export type OptimizerResult = z.infer<typeof optimizerResultSchema>;
export type OptimizerOutput = z.infer<typeof optimizerOutputSchema>;

// =============================================================================
// API Response Schemas
// =============================================================================

export const apiSuccessSchema = <T extends z.ZodType>(dataSchema: T) =>
  z.object({
    success: z.literal(true),
    data: dataSchema,
    meta: z
      .object({
        page: z.number().optional(),
        pageSize: z.number().optional(),
        total: z.number().optional(),
        totalPages: z.number().optional(),
      })
      .optional(),
  });

export const apiErrorSchema = z.object({
  success: z.literal(false),
  error: z.object({
    code: z.string(),
    message: z.string(),
    details: z.record(z.unknown()).optional(),
  }),
});

// =============================================================================
// Auth Schemas
// =============================================================================

export const loginSchema = z.object({
  email: z.string().email('Invalid email format'),
  password: z.string().min(8, 'Password must be at least 8 characters'),
});

export const tokenRefreshSchema = z.object({
  refreshToken: z.string().min(1),
});

export type LoginRequest = z.infer<typeof loginSchema>;
export type TokenRefreshRequest = z.infer<typeof tokenRefreshSchema>;

// =============================================================================
// Scenario Schemas
// =============================================================================

export const scenarioCreateSchema = z.object({
  name: z.string().min(1).max(100),
  description: z.string().max(500).optional(),
  forkedFromBaselineId: uuidSchema.optional(),
  forkedFromScenarioId: uuidSchema.optional(),
});

export const scenarioDeltaSchema = z.object({
  deltaType: z.enum(['PM_MOVE', 'PM_ADD', 'PM_REMOVE', 'CAPACITY_CHANGE', 'TRAIN_STATUS_CHANGE']),
  entityType: z.string(),
  entityId: uuidSchema,
  oldValues: z.record(z.unknown()).optional(),
  newValues: z.record(z.unknown()),
  changeReason: z.string().max(500).optional(),
});

export type ScenarioCreate = z.infer<typeof scenarioCreateSchema>;
export type ScenarioDelta = z.infer<typeof scenarioDeltaSchema>;

// =============================================================================
// Validation Helpers
// =============================================================================

/**
 * Parse and validate data, returning typed result
 */
export function parseSchema<T extends z.ZodType>(
  schema: T,
  data: unknown
): { success: true; data: z.infer<T> } | { success: false; errors: z.ZodError } {
  const result = schema.safeParse(data);
  if (result.success) {
    return { success: true, data: result.data };
  }
  return { success: false, errors: result.error };
}

/**
 * Format Zod errors for API response
 */
export function formatZodErrors(error: z.ZodError): Array<{ field: string; message: string }> {
  return error.errors.map((err) => ({
    field: err.path.join('.'),
    message: err.message,
  }));
}

